code = """import json
import re
from collections import defaultdict

# Direct query for businesses with WiFi - reading from the actual result
businesses = locals()['var_functions.query_db:30']

# For safety, handle string format
if isinstance(businesses, str):
    with open(businesses, 'r') as f:
        businesses = json.load(f)

print(f'Found {len(businesses)} businesses with WiFi attribute')

# Function to extract state from description
def get_state_from_description(desc):
    if not desc:
        return None
    
    # Look for patterns like "in XX," or "in XX." or ", XX "
    match = re.search(r'in ([A-Z]{2})[,\.\s]', desc)
    if match:
        return match.group(1)
    
    # Also check for comma followed by state and zip code
    match = re.search(r', ([A-Z]{2}) \d{5}', desc)
    if match:
        return match.group(1)
    
    return None

# Filter businesses that have WiFi (not 'no') and extract states
wifi_businesses = []
state_business_ids = defaultdict(list)

for biz in businesses:
    # Check if business has WiFi attribute and it's not 'no'
    attributes = biz.get('attributes')
    if attributes and isinstance(attributes, dict):
        wifi = attributes.get('WiFi')
        # Check if WiFi exists and is not 'no'
        if wifi is not None and isinstance(wifi, str):
            # Extract the value from "u'value'" format
            wifi_value = wifi.replace("u'", "").replace("'", "")
            if wifi_value != 'no':  # This business offers WiFi (free or paid)
                state = get_state_from_description(biz.get('description', ''))
                if state:
                    business_id = biz['business_id']
                    wifi_businesses.append({
                        'business_id': business_id,
                        'name': biz['name'],
                        'state': state,
                        'wifi': wifi_value
                    })
                    # Extract business_id number for joining with review table
                    biz_number = business_id.replace('businessid_', '')
                    state_business_ids[state].append(biz_number)

print(f'Found {len(wifi_businesses)} businesses offering WiFi')

# Count businesses per state
state_counts = {state: len(ids) for state, ids in state_business_ids.items()}
print('State counts:', state_counts)

# Find state with highest count
if state_counts:
    max_state = max(state_counts.items(), key=lambda x: x[1])
    result = {
        'wifi_businesses_count': len(wifi_businesses),
        'state_with_most_wifi': max_state[0],
        'count_in_max_state': max_state[1],
        'state_business_ids': dict(state_business_ids),
        'sample_businesses': wifi_businesses[:5]
    }
else:
    result = {'error': 'No WiFi businesses found'}

print('__RESULT__:')
print(json.dumps(result))"""

